mapper.select:
select document_acknowledgement_id, company_id, document_id, user_id, onboarding_id,
       status, read_at, acked_at, created_at
from document_acknowledgements
where company_id = #{companyId,jdbcType=VARCHAR}
  and document_id = #{documentId,jdbcType=VARCHAR}
order by coalesce(read_at, acked_at, created_at) desc nulls last
limit #{limit,jdbcType=INTEGER}
